def load_json(path: Path) -> dict:
    with open(path, encoding="utf-8") as f:
        return json.load(f)


def check_exists(path: Path) -> bool:
    ok = path.exists()
    label = str(path.relative_to(path.anchor) if path.is_absolute() else path)
    if ok:
        print(f"  PASS  {label} exists")
    else:
        print(f"  FAIL  {label} missing")
    return ok


def check_eq(data: dict, key: str, expected: object) -> bool:
    actual = data.get(key)
    ok = actual == expected
    if ok:
        print(f"  PASS  {key} == {expected!r}")
    else:
        print(f"  FAIL  {key} == {actual!r} (expected {expected!r})")
    return ok


def check_has(data: dict, key: str) -> bool:
    ok = key in data
    if ok:
        print(f"  PASS  has key {key!r}")
    else:
        print(f"  FAIL  missing key {key!r}")
    return ok


def check_ge(data: dict, key: str, minimum: int) -> bool:
    actual = data.get(key, -1)
    ok = isinstance(actual, (int, float)) and actual >= minimum
    if ok:
        print(f"  PASS  {key} == {actual} >= {minimum}")
    else:
        print(f"  FAIL  {key} == {actual!r} (expected >= {minimum})")
    return ok


def check_verdict_pass(dir_path: Path, filename: str) -> bool:
    ok = True
    path = dir_path / filename
    if not check_exists(path):
        return False
    data = load_json(path)
    ok &= check_eq(data, "verdict", "PASS")
    return ok


def check_matrix_has_rows(dir_path: Path, filename: str) -> bool:
    ok = True
    path = dir_path / filename
    if not check_exists(path):
        return False
    data = load_json(path)
    ok &= check_has(data, "rows")
    return ok


