def validate_contract_system() -> bool:
    d = CONTRACT_REPORTS
    ok = True
    for f in [
        "contract_system_verdict.json",
        "CONTRACT_SYSTEM_VERDICT.md",
        "contract_acceptance_matrix.json",
        "contract_schema_manifest.json",
        "contract_negative_tests_report.json",
    ]:
        ok &= check_exists(d / f)

    if ok or True:
        v = d / "contract_system_verdict.json"
        if v.exists():
            data = load_json(v)
            ok &= check_eq(data, "classification", "ENTERPRISE_CONTRACT_SYSTEM")
            ok &= check_eq(data, "verdict", "PASS")
            ok &= check_eq(data, "contract_first_agents", "PASS")
            ok &= check_eq(data, "schema_validation", "PASS")
            ok &= check_eq(data, "versioning_and_hashes", "PASS")
            ok &= check_eq(data, "negative_tests", "PASS")
        m = d / "contract_acceptance_matrix.json"
        if m.exists():
            ok &= check_has(load_json(m), "rows")
        n = d / "contract_negative_tests_report.json"
        if n.exists():
            ok &= check_ge(load_json(n), "passed", 0)
    return ok


