ALL_TARGETS = sorted(VALIDATORS.keys())


def main() -> None:
    if len(sys.argv) < 2 or sys.argv[1] in ("-h", "--help"):
        print(f"Usage: {sys.argv[0]} <target>")
        print(f"       {sys.argv[0]} --list")
        print(f"\nAvailable targets ({len(ALL_TARGETS)}):")
        for t in ALL_TARGETS:
            print(f"  {t}")
        sys.exit(0 if "--list" in sys.argv else 1)

    target = sys.argv[1]
    if target == "--list":
        for t in ALL_TARGETS:
            print(t)
        sys.exit(0)

    if target not in VALIDATORS:
        print(f"Unknown target: {target}")
        print(f"Use --list to see available targets")
        sys.exit(1)

    result = VALIDATORS[target]()
    status = "PASS" if result else "FAIL"
    print(f"=== {target} validation: {status} ===")
    sys.exit(0 if result else 1)


if __name__ == "__main__":
    main()
